// ===== CONFIG — edite aqui =====
const PAINEL_URL = 'https://painel.divary.shop';   // URL do Painel na VPS
const N8N_SECRET = 'COLE_O_MESMO_N8N_SECRET_DO_PAINEL';
// Mapa: subdominio do cliente -> credenciais da instancia na Uazapi
const UAZAPI = {
  // 'loja1': { url: 'https://SEU-SERVIDOR.uazapi.com', token: 'TOKEN_DA_INSTANCIA' },
};
// Corpo do "setar webhook" da Uazapi (ajuste conforme a SUA versao):
function corpoWebhookUazapi(webhookUrl) {
  return { enabled: true, url: webhookUrl, events: ['messages'] };
}
// ================================
const semBarra = (s) => (s && s.endsWith('/')) ? s.slice(0, -1) : s;

const body = ($input.first().json.body) || $input.first().json || {};
const chave = body.chave;
const ip = body.ip || null;
if (!chave) throw new Error('chave ausente no corpo do webhook');

// 1) Resolve a chave no Painel (dados do tunel + subdominio)
const cli = await this.helpers.httpRequest({
  method: 'POST',
  url: PAINEL_URL + '/api/enroll/resolve',
  headers: { 'x-n8n-secret': N8N_SECRET },
  body: { chave },
  json: true,
});
const sub = cli.subdominio;
const webhookUrl = cli.webhookUrl;

// 2) Credenciais da Uazapi desse cliente (do mapa acima)
const u = UAZAPI[sub];

// 3) Seta o webhook na instancia da Uazapi (se houver credenciais)
if (u && u.url && u.token) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: semBarra(u.url) + '/webhook',
    headers: { token: u.token, 'Content-Type': 'application/json' },
    body: corpoWebhookUazapi(webhookUrl),
    json: true,
  });
}

// 4) Confirma no Painel (grava o IP local do servidor)
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: PAINEL_URL + '/api/enroll/confirm',
    headers: { 'x-n8n-secret': N8N_SECRET },
    body: { chave, ip },
    json: true,
  });
} catch (e) { /* nao bloqueia */ }

// 5) Resposta que o instalador aplica (frpc.toml + crm-config.json)
return [{ json: {
  ok: true,
  subdominio: sub,
  webhook_url: webhookUrl,
  tunel: cli.tunel,
  uazapi_url: u ? u.url : null,
  uazapi_token: u ? u.token : null,
} }];
